async (params, browser) => {
  // Open top-rated page
  await browser.open(`https://www.rottentomatoes.com/browse/${params.category}?minTomato=70&maxTomato=100&sortBy=sort%3Atomatometer`)

  // Wait for results to load
  await browser.waitForSelector('[data-qa=\'discovery-media-list-item\'], [class*=\'media-list\'], [class*=\'discovery\'], [class*=\'tile\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract top-rated movies
  const top_data = await browser.evaluate(`const movies = []; const items = document.querySelectorAll('[data-qa="discovery-media-list-item"], [class*="media-list"] a, [class*="discovery"] [class*="tile"], [class*="flex-container"] a[href*="/m/"]'); for (let i = 0; i < Math.min(items.length, 20); i++) { const el = items[i]; const titleEl = el.querySelector('[data-qa="discovery-media-list-item-title"], span[class*="title"], [class*="p--small"]'); const tomatometerEl = el.querySelector('rt-text[slot="criticsScore"], [data-qa="tomatometer"], [class*="tomatometer"]'); const audienceEl = el.querySelector('rt-text[slot="audienceScore"], [data-qa="audience-score"]'); const imgEl = el.querySelector('rt-img img, img'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a[href*="/m/"], a[href*="/tv/"]'); movies.push({ rank: i + 1, title: titleEl ? titleEl.textContent.trim() : '', tomatometer: tomatometerEl ? tomatometerEl.textContent.trim() : '', audience_score: audienceEl ? audienceEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.rottentomatoes.com' + linkEl.getAttribute('href')) : '' }); } return { category: params.category || 'movies_at_home', movie_count: movies.length, movies: movies, url: window.location.href }`)

  return top_data
}
